SourceCode.Declaration:
public class HDG_LedgerJournalDelete
{
    private LedgerJournalId journalNum;

}

Method.Source:
public static void main(Args _args)
{
    if (!_args || (_args.dataset() != tableNum(LedgerJournalTable) && _args.dataset() != tableNum(LedgerJournalTrans)))
    {
        throw error(Error::wrongUseOfFunction(funcName()));
    }

    HDG_LedgerJournalDelete ledgerJournalDelete = new HDG_LedgerJournalDelete();

    if(_args.dataset() == tableNum(LedgerJournalTrans))
    {
        LedgerJournalTrans ledgerJournalTrans = _args.record() as LedgerJournalTrans;
        ledgerJournalDelete.parmJournalNum(ledgerJournalTrans.JournalNum);
    }
    else if(_args.dataset() == tableNum(LedgerJournalTable))
    {
        LedgerJournalTable ledgerJournalTable = _args.record() as LedgerJournalTable;
        ledgerJournalDelete.parmJournalNum(ledgerJournalTable.JournalNum);
    }

    ledgerJournalDelete.run();
}

public LedgerJournalId parmJournalNum(LedgerJournalId _journalNum = journalNum)
{
    journalNum = _journalNum;
    return journalNum;
}

public void run()
{
    LedgerJournalTable ledgerJournalTable = LedgerJournalTable::find(journalNum);

    Args args = new Args();
    args.parm('DeleteJournal');
    args.record(ledgerJournalTable);

    LedgerJournalDeleteTransaction::main(args, false);

    delete_from ledgerJournalTable
        where ledgerJournalTable.JournalNum == journalNum;
}
